select coalesce(sum(amount), 0)
from supervision_account_log
where institution_id = #{institutionId}
    and transaction_type = '支出'
    and transaction_time <= #{transactionTime}




     and sal.institution_id = #{institutionId}
     and sal.transaction_no like concat('%', #{transactionNo}, '%')
     and sal.transaction_type = #{transactionType}
     and sal.business_type = #{businessType}
     and sal.counterparty like concat('%', #{counterparty}, '%')

        and date_format(sal.transaction_time,'%y%m%d') >= date_format(#{params.beginTime},'%y%m%d')


        and date_format(sal.transaction_time,'%y%m%d') <= date_format(#{params.endTime},'%y%m%d')


order by sal.transaction_time desc

SELECT ft.transfer_id as transferId, ft.transfer_no as transferNo, ft.institution_id as institutionId, ft.elder_id as elderId, ft.order_id as orderId, ft.billing_month as billingMonth, ft.transfer_amount as transferAmount, ft.transfer_date as transferDate, ft.transfer_type as transferType, ft.paid_time as paidTime, ft.remark as remark, ft.create_time as createTime, ei.elder_name as elderName, pi.institution_name as institutionName, oi.order_no as orderNo, (SELECT COALESCE(sal.balance_after, 0) FROM supervision_account_log sal WHERE sal.institution_id = ft.institution_id AND sal.transaction_time <= ft.paid_time ORDER BY sal.transaction_time DESC LIMIT 1) as supervisionBalance, (SELECT COALESCE(SUM(ft2.transfer_amount), 0) FROM fund_transfer ft2 WHERE ft2.institution_id = ft.institution_id AND ft2.status = 'completed' AND ft2.is_paid = '1' AND ft2.paid_time <= ft.paid_time AND ft2.transfer_id <= ft.transfer_id) as basicBalance FROM fund_transfer ft LEFT JOIN elder_info ei ON ft.elder_id = ei.elder_id LEFT JOIN pension_institution pi ON ft.institution_id = pi.institution_id LEFT JOIN order_info oi ON ft.order_id = oi.order_id
-- 只查询已划拨完成的记录（监管账户转到基本账户） ft.status = 'completed' AND ft.is_paid = '1'
AND ft.institution_id IN ( SELECT institution_id FROM sys_user_institution WHERE user_id = #{params.currentUserId} )
AND ft.institution_id = #{params.institutionId}
AND ft.transfer_type = #{params.transferType}
AND DATE_FORMAT(ft.transfer_date, '%Y-%m-%d') >= #{params.beginTime}
AND DATE_FORMAT(ft.transfer_date, '%Y-%m-%d') <= #{params.endTime}
AND ei.elder_name LIKE CONCAT('%', #{params.elderName}, '%')
ORDER BY ft.paid_time DESC

SELECT ft.transfer_id as transferId, ft.transfer_no as transferNo, ft.transfer_type as transferType, ft.transfer_amount as transferAmount, ft.transfer_date as transferDate, ft.billing_month as billingMonth, ft.status as status, ft.is_paid as isPaid, ft.paid_time as paidTime, ft.create_time as createTime, ft.remark as remark, ft.elder_id as elderId, ft.institution_id as institutionId, ft.order_id as orderId, ei.elder_name as elderName, pi.institution_name as institutionName, oi.order_no as orderNo, (SELECT COALESCE(sal.balance_after, 0) FROM supervision_account_log sal WHERE sal.institution_id = ft.institution_id ORDER BY sal.transaction_time DESC LIMIT 1) as supervisionBalance FROM fund_transfer ft LEFT JOIN elder_info ei ON ft.elder_id = ei.elder_id LEFT JOIN pension_institution pi ON ft.institution_id = pi.institution_id LEFT JOIN order_info oi ON ft.order_id = oi.order_id
AND ft.institution_id IN ( SELECT institution_id FROM sys_user_institution WHERE user_id = #{params.currentUserId} )
AND ft.transfer_no LIKE CONCAT('%', #{params.transferNo}, '%')
AND ft.transfer_type = #{params.transferType}
AND ei.elder_name LIKE CONCAT('%', #{params.elderName}, '%')
AND ft.status = #{params.status}
AND DATE_FORMAT(ft.create_time, '%Y-%m-%d') >= #{params.beginTime}
AND DATE_FORMAT(ft.create_time, '%Y-%m-%d') <= #{params.endTime}
ORDER BY ft.billing_month ASC

SELECT COALESCE(SUM(deposit_balance), 0)
FROM account_info
WHERE institution_id = #{institutionId}
